import React, { useEffect, useRef, useContext } from 'react';
import { Link } from 'react-router-dom';
import { motion, useScroll, useTransform } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import Particles from 'react-tsparticles';
import { loadSlim } from 'tsparticles-slim';
import { 
  Download, Github, Linkedin, Twitter, Mail, ChevronRight,
  Brain, Database, BarChart, Cpu, Sparkles, Zap, 
  Award, BookOpen, MapPin, Calendar, ExternalLink, 
  TrendingUp, Code, Cloud, Users, Target, Trophy,
  Flame, Medal, CheckCircle, Clock, Activity
} from 'lucide-react';
import { mlProjects, testimonials, contactInfo, skills, certifications } from '../data/mockData';
import { ThemeContext } from '../App';
import styles from './Home.module.css';

const Home = () => {
  const containerRef = useRef(null);
  const { theme } = useContext(ThemeContext);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end start"]
  });

  const y = useTransform(scrollYProgress, [0, 1], ['0%', '50%']);
  const opacity = useTransform(scrollYProgress, [0, 0.5], [1, 0]);

  const [heroRef, heroInView] = useInView({
    threshold: 0.1,
    triggerOnce: true
  });

  const particlesInit = async (engine) => {
    await loadSlim(engine);
  };

  const particlesOptions = {
    particles: {
      number: { value: 80, density: { enable: true, value_area: 800 } },
      color: { value: theme === 'dark' ? "#10b981" : "#10b981" },
      shape: { type: "circle" },
      opacity: { value: 0.3, random: true, anim: { enable: true, speed: 1, opacity_min: 0.1 } },
      size: { value: 2, random: true, anim: { enable: true, speed: 2, size_min: 0.1 } },
      line_linked: { enable: true, distance: 150, color: "#10b981", opacity: 0.2, width: 1 },
      move: { enable: true, speed: 1, direction: "none", random: true, straight: false, out_mode: "out" }
    },
    interactivity: {
      detect_on: "canvas",
      events: { onhover: { enable: true, mode: "grab" }, onclick: { enable: true, mode: "push" }, resize: true },
      modes: { grab: { distance: 140, line_linked: { opacity: 0.5 } }, push: { particles_nb: 4 } }
    },
    retina_detect: true
  };

  const mlAchievements = [
    {
      title: 'Kaggle Expert',
      description: 'Achieved top 10% in 3 competitions',
      icon: <Trophy />,
      date: '2024',
      color: '#f59e0b',
      metric: 'Top 10%'
    },
    {
      title: 'Research Publications',
      description: '3 papers published in international conferences',
      icon: <BookOpen />,
      date: '2023-2024',
      color: '#10b981',
      metric: '3 Papers'
    },
    {
      title: 'Open Source ML',
      description: 'Contributions to TensorFlow and PyTorch',
      icon: <Code />,
      date: '2024',
      color: '#8b5cf6',
      metric: '10+ PRs'
    },
    {
      title: 'Hackathon Winner',
      description: '1st place at AI for Good Hackathon',
      icon: <Medal />,
      date: '2024',
      color: '#ec489a',
      metric: 'National Level'
    }
  ];

  const codingStats = [
    { platform: 'Kaggle', problems: 15, icon: <TrendingUp />, color: '#20BEFF', metric: 'Expert' },
    { platform: 'LeetCode', problems: 300, icon: <Target />, color: '#f97316', metric: '1500+ rating' },
    { platform: 'HackerRank', problems: 200, icon: <Medal />, color: '#10b981', metric: '5-star' },
    { platform: 'GitHub', problems: 25, icon: <Code />, color: '#8b5cf6', metric: 'Repositories' }
  ];

  const techStack = [
    { name: 'TensorFlow', level: 90, icon: '🧠', color: '#FF6F00' },
    { name: 'PyTorch', level: 85, icon: '🔥', color: '#EE4C2C' },
    { name: 'Scikit-learn', level: 88, icon: '📊', color: '#F7931E' },
    { name: 'Python', level: 92, icon: '🐍', color: '#3776AB' },
    { name: 'Transformers', level: 82, icon: '🤗', color: '#FFD21E' },
    { name: 'OpenCV', level: 80, icon: '👁️', color: '#5C3EE8' }
  ];

  const featuredProjects = mlProjects.filter(p => p.featured).slice(0, 3);

  return (
    <div className={styles.container} ref={containerRef}>
      <Particles
        id="tsparticles"
        init={particlesInit}
        options={particlesOptions}
        className={styles.particles}
      />

      <motion.section 
        ref={heroRef}
        className={styles.hero}
        style={{ y, opacity }}
      >
        <div className={styles.heroContent}>
          <motion.div 
            className={styles.heroText}
            initial={{ opacity: 0, x: -50 }}
            animate={heroInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 0.8, delay: 0.2 }}
          >
            <motion.span 
              className={styles.greeting}
              initial={{ opacity: 0, y: 20 }}
              animate={heroInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.5 }}
            >
              🤖 AI/ML Engineer
            </motion.span>
            
            <motion.h1 
              className={styles.name}
              initial={{ opacity: 0, y: 30 }}
              animate={heroInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: 0.3 }}
            >
              Aditya <span className={styles.highlight}>Raj</span>
            </motion.h1>

            <motion.h2 
              className={styles.title}
              initial={{ opacity: 0, y: 30 }}
              animate={heroInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: 0.4 }}
            >
              Building Intelligent Systems with AI & Machine Learning
            </motion.h2>

            <motion.p 
              className={styles.bio}
              initial={{ opacity: 0, y: 30 }}
              animate={heroInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: 0.5 }}
            >
              Passionate about leveraging machine learning and deep learning to solve real-world problems.
              Published researcher with expertise in Computer Vision, NLP, and Model Deployment.
              Kaggle Expert with top 10% rankings in multiple competitions.
            </motion.p>

            <motion.div 
              className={styles.infoTags}
              initial={{ opacity: 0, y: 30 }}
              animate={heroInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: 0.6 }}
            >
              <span className={styles.tag}>
                <MapPin className={styles.tagIcon} /> Punjab, India
              </span>
              <span className={styles.tag}>
                <Brain className={styles.tagIcon} /> AI/ML Specialist
              </span>
              <span className={styles.tag}>
                <Activity className={styles.tagIcon} /> 3 Publications
              </span>
              <span className={styles.tag}>
                <Trophy className={styles.tagIcon} /> Kaggle Expert
              </span>
            </motion.div>

            <motion.div 
              className={styles.cvSection}
              initial={{ opacity: 0, y: 30 }}
              animate={heroInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: 0.7 }}
            >
              <div className={styles.cvButtons}>
                <motion.a
                  href="#"
                  download
                  className={`${styles.cvButton} ${styles.cvButtonPrimary}`}
                  whileHover={{ scale: 1.05, y: -2 }}
                  whileTap={{ scale: 0.95 }}
                >
                  <Download className={styles.buttonIcon} />
                  Download Resume
                  <span className={styles.buttonBadge}>PDF</span>
                </motion.a>
                <motion.a
                  href="#"
                  className={`${styles.cvButton} ${styles.cvButtonSecondary}`}
                  whileHover={{ scale: 1.05, y: -2 }}
                  whileTap={{ scale: 0.95 }}
                >
                  View Research Papers
                  <ChevronRight className={styles.buttonIcon} />
                </motion.a>
              </div>
            </motion.div>

            <motion.div 
              className={styles.socialLinks}
              initial={{ opacity: 0, y: 30 }}
              animate={heroInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: 0.8 }}
            >
              <motion.a 
                href={contactInfo.social.github} 
                className={styles.socialLink}
                whileHover={{ y: -5, rotate: 360 }}
                whileTap={{ scale: 0.9 }}
              >
                <Github />
              </motion.a>
              <motion.a 
                href={contactInfo.social.linkedin} 
                className={styles.socialLink}
                whileHover={{ y: -5, rotate: 360 }}
                whileTap={{ scale: 0.9 }}
              >
                <Linkedin />
              </motion.a>
              <motion.a 
                href={contactInfo.social.twitter} 
                className={styles.socialLink}
                whileHover={{ y: -5, rotate: 360 }}
                whileTap={{ scale: 0.9 }}
              >
                <Twitter />
              </motion.a>
              <motion.a 
                href={contactInfo.social.kaggle} 
                className={styles.socialLink}
                whileHover={{ y: -5, rotate: 360 }}
                whileTap={{ scale: 0.9 }}
              >
                <TrendingUp />
              </motion.a>
            </motion.div>
          </motion.div>

          <motion.div 
            className={styles.heroVisual}
            initial={{ opacity: 0, x: 50 }}
            animate={heroInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 0.8, delay: 0.4 }}
          >
            <div className={styles.profileCard}>
              <motion.div 
                className={styles.profileImageWrapper}
                whileHover={{ scale: 1.05 }}
                transition={{ type: "spring", stiffness: 300 }}
              >
                <img
                  src="https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?auto=format&fit=crop&w=800&q=80"
                  alt="Aditya Raj"
                  className={styles.profileImage}
                />
                <div className={styles.statusIndicator}></div>
              </motion.div>

              <div className={styles.stats}>
                <motion.div className={styles.statItem} whileHover={{ scale: 1.1 }}>
                  <span className={styles.statValue}>3+</span>
                  <span className={styles.statLabel}>Publications</span>
                </motion.div>
                <div className={styles.statDivider}></div>
                <motion.div className={styles.statItem} whileHover={{ scale: 1.1 }}>
                  <span className={styles.statValue}>15+</span>
                  <span className={styles.statLabel}>ML Projects</span>
                </motion.div>
                <div className={styles.statDivider}></div>
                <motion.div className={styles.statItem} whileHover={{ scale: 1.1 }}>
                  <span className={styles.statValue}>500+</span>
                  <span className={styles.statLabel}>Problems Solved</span>
                </motion.div>
              </div>

              <motion.div 
                className={styles.streakBadge}
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                transition={{ delay: 1, type: "spring" }}
              >
                <Brain className={styles.streakIcon} />
                <div>
                  <strong>ML Research</strong>
                  <span>3 Papers Published</span>
                </div>
              </motion.div>
            </div>
          </motion.div>
        </div>
      </motion.section>

      <section className={styles.codingStats}>
        <motion.h2 
          className={styles.sectionTitle}
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          <span className={styles.sectionTitleAccent}>Achievements</span>
          <span className={styles.sectionTitleMain}>Coding & Competition Stats</span>
        </motion.h2>
        
        <div className={styles.statsGrid}>
          {codingStats.map((stat, index) => (
            <motion.div
              key={index}
              className={styles.codingStatCard}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              viewport={{ once: true }}
              whileHover={{ y: -5 }}
            >
              <div className={styles.codingStatIcon} style={{ background: `${stat.color}20`, color: stat.color }}>
                {stat.icon}
              </div>
              <div className={styles.codingStatInfo}>
                <h3>{stat.platform}</h3>
                <div className={styles.codingStatNumber}>{stat.problems}+</div>
                <div className={styles.codingStatLabel}>{stat.metric}</div>
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      <section className={styles.achievements}>
        <motion.h2 
          className={styles.sectionTitle}
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          <span className={styles.sectionTitleAccent}>Milestones</span>
          <span className={styles.sectionTitleMain}>Key Achievements</span>
        </motion.h2>

        <div className={styles.achievementsGrid}>
          {mlAchievements.map((achievement, index) => (
            <motion.div
              key={index}
              className={styles.achievementCard}
              initial={{ opacity: 0, y: 50 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              viewport={{ once: true }}
              whileHover={{ y: -10 }}
            >
              <div 
                className={styles.achievementIcon}
                style={{ background: `${achievement.color}20`, color: achievement.color }}
              >
                {achievement.icon}
              </div>
              <h3 className={styles.achievementTitle}>{achievement.title}</h3>
              <p className={styles.achievementDescription}>{achievement.description}</p>
              <div className={styles.achievementMeta}>
                <span className={styles.achievementDate}>
                  <Calendar className={styles.metaIcon} />
                  {achievement.date}
                </span>
                <span className={styles.achievementMetric} style={{ background: `${achievement.color}20`, color: achievement.color }}>
                  {achievement.metric}
                </span>
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      <section className={styles.featured}>
        <motion.h2 
          className={styles.sectionTitle}
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          <span className={styles.sectionTitleAccent}>Portfolio</span>
          <span className={styles.sectionTitleMain}>Featured ML Projects</span>
        </motion.h2>

        <div className={styles.projectsGrid}>
          {featuredProjects.map((project, index) => (
            <motion.div
              key={project.id}
              className={styles.projectCard}
              initial={{ opacity: 0, y: 50 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.2 }}
              viewport={{ once: true }}
              whileHover={{ y: -15 }}
            >
              <div className={styles.projectImageWrapper}>
                <img src={project.image} alt={project.title} className={styles.projectImage} />
                <div className={styles.projectOverlay}>
                  <motion.a 
                    href={project.github}
                    className={styles.projectLink}
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    <Github /> Code
                  </motion.a>
                  <motion.a 
                    href={project.live}
                    className={styles.projectLink}
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    <ExternalLink /> Demo
                  </motion.a>
                </div>
                <div className={styles.completionBadge}>
                  {project.accuracy || project.fps}
                </div>
              </div>
              <div className={styles.projectContent}>
                <h3 className={styles.projectTitle}>{project.title}</h3>
                <p className={styles.projectDescription}>{project.description}</p>
                <div className={styles.projectTags}>
                  {project.tags.slice(0, 3).map(tag => (
                    <span key={tag} className={styles.projectTag}>{tag}</span>
                  ))}
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        <motion.div 
          className={styles.viewAllContainer}
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
        >
          <Link to="/projects" className={styles.viewAllButton}>
            View All Projects <ChevronRight />
          </Link>
        </motion.div>
      </section>

      <section className={styles.techStack}>
        <motion.h2 
          className={styles.sectionTitle}
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          <span className={styles.sectionTitleAccent}>Expertise</span>
          <span className={styles.sectionTitleMain}>Tech Stack & Tools</span>
        </motion.h2>

        <div className={styles.techStackGrid}>
          {techStack.map((tech, index) => (
            <motion.div
              key={index}
              className={styles.techCard}
              initial={{ opacity: 0, scale: 0.9 }}
              whileInView={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              viewport={{ once: true }}
              whileHover={{ y: -5 }}
            >
              <div className={styles.techIcon} style={{ background: `${tech.color}20`, color: tech.color }}>
                <span>{tech.icon}</span>
              </div>
              <div className={styles.techInfo}>
                <h4>{tech.name}</h4>
                <div className={styles.techProgressBar}>
                  <div 
                    className={styles.techProgressFill}
                    style={{ width: `${tech.level}%`, background: tech.color }}
                  />
                </div>
                <span className={styles.techLevel}>{tech.level}%</span>
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      <section className={styles.testimonials}>
        <motion.h2 
          className={styles.sectionTitle}
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          <span className={styles.sectionTitleAccent}>Testimonials</span>
          <span className={styles.sectionTitleMain}>What People Say</span>
        </motion.h2>

        <div className={styles.testimonialsGrid}>
          {testimonials.map((testimonial, index) => (
            <motion.div
              key={testimonial.id}
              className={styles.testimonialCard}
              initial={{ opacity: 0, x: index % 2 === 0 ? -50 : 50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6, delay: index * 0.2 }}
              viewport={{ once: true }}
              whileHover={{ scale: 1.02 }}
            >
              <div className={styles.testimonialHeader}>
                <img src={testimonial.avatar} alt={testimonial.name} />
                <div>
                  <h4>{testimonial.name}</h4>
                  <p>{testimonial.position}</p>
                </div>
              </div>
              <p className={styles.testimonialText}>"{testimonial.text}"</p>
              <div className={styles.testimonialRating}>
                {[...Array(testimonial.rating)].map((_, i) => (
                  <Sparkles key={i} className={styles.starFilled} />
                ))}
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      <motion.section 
        className={styles.cta}
        initial={{ opacity: 0, scale: 0.9 }}
        whileInView={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.8 }}
        viewport={{ once: true }}
      >
        <div className={styles.ctaContent}>
          <h2 className={styles.ctaTitle}>Let's Build Something Intelligent</h2>
          <p className={styles.ctaText}>
            I'm actively looking for AI/ML research opportunities and collaboration on innovative projects.
            With published research and multiple successful ML projects, I'm ready to contribute to cutting-edge AI solutions.
          </p>
          <motion.div 
            className={styles.ctaButtons}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            <a href="mailto:adityaraj@example.com" className={styles.ctaButton}>
              <Mail /> Get in Touch
            </a>
          </motion.div>
        </div>
      </motion.section>
    </div>
  );
};

export default Home;
